const matches = $input.all();
const results = [];
for (const match of matches) {
  const data = match.json;
  results.push({
    json: {
      category: data.category || 'men',
      round: parseInt(data.round) || 1,
      round_name: data.round_name || 'Finals',
      index: parseInt(data.index) || 0,
      court: data.court || 'Unknown',
      competition_source: data.competition_source || 'FIP',
      month: new Date(data.played_at || Date.now()).getMonth() + 1,
      winner_enc: data.winner === 'team_1' ? 1 : 0,
      duration_filled: data.duration_minutes !== 'Unknown' && data.duration_minutes ? parseFloat(data.duration_minutes) : 87.0,
      match_id: String(data.match_id || data.id || 'N/A'),
      match_name: data.name || 'Unknown'
    }
  });
}
return results;

const items = $input.all();
const results = [];
const clusterProfiles = {
  0: { name: 'FIP Circuit Matches', description: 'High round numbers, FIP circuit dominant', color: '#2EC878' },
  1: { name: 'WPT Circuit Matches', description: 'WPT circuit, different round structure', color: '#3B9EE8' }
};
for (const item of items) {
  const d = item.json;
  const clusterId = d.cluster !== undefined ? d.cluster : 0;
  const profile = clusterProfiles[clusterId] || clusterProfiles[0];
  results.push({
    json: {
      match_id: d.match_id || 'N/A',
      cluster_id: clusterId,
      cluster_name: profile.name,
      cluster_description: profile.description,
      model: 'KMeans k=2 (Silhouette=0.216)',
      timestamp: new Date().toISOString()
    }
  });
}
const cluster0 = results.filter(r => r.json.cluster_id === 0).length;
const cluster1 = results.filter(r => r.json.cluster_id === 1).length;
results.push({
  json: {
    summary: true,
    total_matches: results.length,
    cluster_0_count: cluster0,
    cluster_1_count: cluster1,
    cluster_0_pct: ((cluster0 / results.length) * 100).toFixed(1) + '%',
    cluster_1_pct: ((cluster1 / results.length) * 100).toFixed(1) + '%',
    timestamp: new Date().toISOString()
  }
});
return results;

const items = $input.all();
const summary = items.find(i => i.json.summary === true);
if (!summary) return items;
const cluster0Pct = parseFloat(summary.json.cluster_0_pct);
const driftDetected = Math.abs(cluster0Pct - 64.2) > 10;
return [{ json: {
  ...summary.json,
  drift_detected: driftDetected,
  drift_alert: driftDetected ? `⚠️ Cluster distribution shifted! Expected ~64% FIP, got ${summary.json.cluster_0_pct}` : null,
  baseline_cluster0_pct: '64.2%'
}}];

const items = $input.all();
const driftInfo = items[0]?.json || {};
const alert = {
  type: 'CLUSTER_DRIFT_ALERT',
  pipeline: 'Clustering — Match Segments',
  timestamp: new Date().toISOString(),
  message: driftInfo.drift_alert,
  current_distribution: { cluster_0: driftInfo.cluster_0_pct, cluster_1: driftInfo.cluster_1_pct },
  baseline_distribution: { cluster_0: '64.2%', cluster_1: '35.8%' },
  recommendation: 'Consider retraining KMeans model with new data'
};
await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://127.0.0.1:5000/log_error',
  headers: { 'Content-Type': 'application/json' },
  body: alert,
  json: true
});
return [{ json: alert }];

const items = $input.all();
const predictions = items
  .filter(i => !i.json.summary && !i.json.drift_detected)
  .map(item => ({
    match_id: item.json.match_id || 'N/A',
    predicted_winner: item.json.cluster_name || 'Unknown',
    probability_team1: item.json.cluster_id || 0,
    probability_team2: 0,
    timestamp: item.json.timestamp || new Date().toISOString()
  }));
if (predictions.length === 0) return [{ json: { saved: false, reason: 'no data' } }];
const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://127.0.0.1:5000/save_predictions',
  headers: { 'Content-Type': 'application/json' },
  body: { predictions },
  json: true
});
return [{ json: response }];
